import{_ as i,o as a,c as n,ae as t}from"./chunks/framework.CB71nIlf.js";const d=JSON.parse('{"title":"通过邮件邀请","description":"","frontmatter":{},"headers":[],"relativePath":"2-experimenter-manual/5-invite-system/5-2-send-email.md","filePath":"2-experimenter-manual/5-invite-system/5-2-send-email.md"}'),r={name:"2-experimenter-manual/5-invite-system/5-2-send-email.md"};function o(e,l,s,u,p,h){return a(),n("div",null,[...l[0]||(l[0]=[t(`<h1 id="通过邮件邀请" tabindex="-1">通过邮件邀请 <a class="header-anchor" href="#通过邮件邀请" aria-label="Permalink to &quot;通过邮件邀请&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>邮件邀请是批量邀请被试的高效方式。通过邮件邀请功能，您可以向多个邮箱地址发送个性化的邀请邮件，邮件中包含您的专属邀请链接和自定义消息。这种方式适合向特定的被试群体发送邀请，提高邀请的针对性和转化率。</p><h2 id="进入邮件邀请" tabindex="-1">进入邮件邀请 <a class="header-anchor" href="#进入邮件邀请" aria-label="Permalink to &quot;进入邮件邀请&quot;">​</a></h2><p>登录后，进入&quot;邀请用户&quot;页面，在页面右侧找到&quot;通过邮件邀请&quot;区域。</p><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h2><h3 id="_1-添加收件人" tabindex="-1">1. 添加收件人 <a class="header-anchor" href="#_1-添加收件人" aria-label="Permalink to &quot;1. 添加收件人&quot;">​</a></h3><h4 id="_1-1-邮箱输入" tabindex="-1">1.1 邮箱输入 <a class="header-anchor" href="#_1-1-邮箱输入" aria-label="Permalink to &quot;1.1 邮箱输入&quot;">​</a></h4><p><strong>输入框位置</strong>：页面右侧顶部</p><p><strong>输入方式</strong>：</p><ul><li>在邮箱输入框中输入收件人的邮箱地址</li><li>支持标准的邮箱格式（如：example@email.com）</li><li>输入完成后点击&quot;添加&quot;按钮或按Enter键</li></ul><p><strong>邮箱验证</strong>：</p><ul><li>系统自动验证邮箱格式</li><li>无效的邮箱地址无法添加</li><li>重复的邮箱地址会被提示</li></ul><p><strong>快捷操作</strong>：</p><ul><li>按Enter键快速添加邮箱</li><li>无需每次都点击&quot;添加&quot;按钮</li><li>提高批量添加效率</li></ul><h4 id="_1-2-收件人列表" tabindex="-1">1.2 收件人列表 <a class="header-anchor" href="#_1-2-收件人列表" aria-label="Permalink to &quot;1.2 收件人列表&quot;">​</a></h4><p><strong>列表显示</strong>：</p><ul><li>位于邮箱输入框下方</li><li>显示所有已添加的邮箱地址</li><li>列表可滚动查看（最大高度32）</li><li>显示收件人总数</li></ul><p><strong>列表管理</strong>：</p><ul><li>每个邮箱地址右侧有删除按钮（×）</li><li>点击删除按钮移除该邮箱</li><li>支持逐个删除或全部清空</li></ul><p><strong>收件人数量</strong>：</p><ul><li>实时显示已添加的收件人数量</li><li>格式：&quot;{数量} 位收件人&quot;</li><li>帮助您掌握邀请规模</li></ul><h3 id="_2-编写邀请消息" tabindex="-1">2. 编写邀请消息 <a class="header-anchor" href="#_2-编写邀请消息" aria-label="Permalink to &quot;2. 编写邀请消息&quot;">​</a></h3><h4 id="_2-1-消息输入框" tabindex="-1">2.1 消息输入框 <a class="header-anchor" href="#_2-1-消息输入框" aria-label="Permalink to &quot;2.1 消息输入框&quot;">​</a></h4><p><strong>位置</strong>：收件人列表下方</p><p><strong>输入方式</strong>：</p><ul><li>多行文本框</li><li>支持换行和段落</li><li>最大长度：300字符</li></ul><p><strong>字符计数</strong>：</p><ul><li>实时显示已输入字符数</li><li>格式：&quot;{已输入}/{最大长度}&quot;</li><li>超过限制无法继续输入</li></ul><h4 id="_2-2-消息内容建议" tabindex="-1">2.2 消息内容建议 <a class="header-anchor" href="#_2-2-消息内容建议" aria-label="Permalink to &quot;2.2 消息内容建议&quot;">​</a></h4><p><strong>推荐内容</strong>：</p><ol><li><p><strong>自我介绍</strong>：</p><ul><li>简要介绍您的身份和研究背景</li><li>说明您的研究机构或团队</li></ul></li><li><p><strong>邀请目的</strong>：</p><ul><li>说明为什么邀请对方参与</li><li>强调实验的意义和价值</li></ul></li><li><p><strong>实验简介</strong>：</p><ul><li>简要描述实验内容</li><li>说明实验时长和要求</li></ul></li><li><p><strong>参与激励</strong>：</p><ul><li>说明参与实验的好处</li><li>如有报酬或奖励，请明确说明</li></ul></li><li><p><strong>联系方式</strong>：</p><ul><li>提供您的联系方式</li><li>方便被试咨询和沟通</li></ul></li></ol><p><strong>消息示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>您好！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我是XX大学心理学系的研究生，正在进行一项关于认知功能的研究。</span></span>
<span class="line"><span>诚挚邀请您参与我们的在线实验，实验大约需要20分钟。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>通过参与实验，您将：</span></span>
<span class="line"><span>- 了解自己的认知特点</span></span>
<span class="line"><span>- 为科学研究贡献力量</span></span>
<span class="line"><span>- 获得实验报告反馈</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如有任何疑问，欢迎随时联系我。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>期待您的参与！</span></span></code></pre></div><h4 id="_2-3-消息注意事项" tabindex="-1">2.3 消息注意事项 <a class="header-anchor" href="#_2-3-消息注意事项" aria-label="Permalink to &quot;2.3 消息注意事项&quot;">​</a></h4><p><strong>避免内容</strong>：</p><ul><li>不要包含虚假信息</li><li>不要使用误导性的宣传</li><li>不要承诺无法兑现的奖励</li><li>不要泄露被试的个人信息</li></ul><p><strong>语言建议</strong>：</p><ul><li>使用礼貌、专业的语言</li><li>简洁明了，避免冗长</li><li>突出重点，吸引注意</li><li>真诚友好，建立信任</li></ul><h3 id="_3-发送邀请邮件" tabindex="-1">3. 发送邀请邮件 <a class="header-anchor" href="#_3-发送邀请邮件" aria-label="Permalink to &quot;3. 发送邀请邮件&quot;">​</a></h3><h4 id="_3-1-发送操作" tabindex="-1">3.1 发送操作 <a class="header-anchor" href="#_3-1-发送操作" aria-label="Permalink to &quot;3.1 发送操作&quot;">​</a></h4><p><strong>操作步骤</strong>：</p><ol><li>确认收件人列表无误</li><li>检查邀请消息内容</li><li>点击&quot;发送邀请邮件&quot;按钮</li><li>等待发送完成</li></ol><p><strong>发送状态</strong>：</p><ul><li>发送中：按钮显示加载动画</li><li>发送成功：显示成功提示</li><li>发送失败：显示错误信息</li></ul><h4 id="_3-2-邮件内容" tabindex="-1">3.2 邮件内容 <a class="header-anchor" href="#_3-2-邮件内容" aria-label="Permalink to &quot;3.2 邮件内容&quot;">​</a></h4><p><strong>邮件组成</strong>：</p><ol><li><p><strong>邮件主题</strong>：</p><ul><li>自动生成，包含&quot;邀请&quot;关键词</li><li>吸引收件人打开邮件</li></ul></li><li><p><strong>个性化消息</strong>：</p><ul><li>您编写的自定义消息</li><li>显示在邮件顶部</li></ul></li><li><p><strong>邀请链接</strong>：</p><ul><li>您的专属邀请链接</li><li>点击即可跳转到注册页面</li></ul></li><li><p><strong>平台介绍</strong>：</p><ul><li>CogniAND平台的简介</li><li>平台的特点和优势</li></ul></li><li><p><strong>注册指引</strong>：</p><ul><li>简单的注册步骤说明</li><li>帮助被试快速完成注册</li></ul></li></ol><h4 id="_3-3-发送后处理" tabindex="-1">3.3 发送后处理 <a class="header-anchor" href="#_3-3-发送后处理" aria-label="Permalink to &quot;3.3 发送后处理&quot;">​</a></h4><p><strong>自动操作</strong>：</p><ul><li>清空收件人列表</li><li>清空邀请消息</li><li>保存邀请记录到本地</li><li>更新邀请统计</li></ul><p><strong>邀请记录</strong>：</p><ul><li>记录发送时间</li><li>记录收件人邮箱列表</li><li>记录邀请消息内容</li><li>记录邀请链接</li></ul><h3 id="_4-查看邀请记录" tabindex="-1">4. 查看邀请记录 <a class="header-anchor" href="#_4-查看邀请记录" aria-label="Permalink to &quot;4. 查看邀请记录&quot;">​</a></h3><h4 id="_4-1-本地记录" tabindex="-1">4.1 本地记录 <a class="header-anchor" href="#_4-1-本地记录" aria-label="Permalink to &quot;4.1 本地记录&quot;">​</a></h4><p><strong>存储位置</strong>：</p><ul><li>邀请记录保存在浏览器本地存储中</li><li>记录格式：JSON数据</li></ul><p><strong>记录内容</strong>：</p><ul><li>邀请ID</li><li>用户ID</li><li>收件人邮箱列表</li><li>邀请消息</li><li>发送时间</li><li>邀请链接</li></ul><h4 id="_4-2-查看历史" tabindex="-1">4.2 查看历史 <a class="header-anchor" href="#_4-2-查看历史" aria-label="Permalink to &quot;4.2 查看历史&quot;">​</a></h4><p><strong>查看方式</strong>：</p><ul><li>在个人中心查看详细的邀请历史</li><li>包括每次邀请的详细信息</li><li>可以查看邀请的注册转化情况</li></ul><p>详细的邀请历史查看请参考<a href="/cogniand-manual.github.io/3-subject-manual/5-personal-center.html">个人中心</a>。</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><h3 id="_1-选择合适的收件人" tabindex="-1">1. 选择合适的收件人 <a class="header-anchor" href="#_1-选择合适的收件人" aria-label="Permalink to &quot;1. 选择合适的收件人&quot;">​</a></h3><p><strong>目标群体</strong>：</p><ul><li>符合实验要求的被试</li><li>对研究主题感兴趣的人群</li><li>有时间和意愿参与的人员</li></ul><p><strong>获取邮箱</strong>：</p><ul><li>通过学术网络获取</li><li>通过专业社区获取</li><li>通过合作机构获取</li><li>确保邮箱来源合法</li></ul><p><strong>避免事项</strong>：</p><ul><li>不要购买邮箱列表</li><li>不要发送垃圾邮件</li><li>不要向不相关的人发送</li><li>不要频繁发送重复邮件</li></ul><h3 id="_2-优化邀请消息" tabindex="-1">2. 优化邀请消息 <a class="header-anchor" href="#_2-优化邀请消息" aria-label="Permalink to &quot;2. 优化邀请消息&quot;">​</a></h3><p><strong>提高打开率</strong>：</p><ul><li>使用吸引人的邮件主题</li><li>在消息开头说明重点</li><li>保持消息简洁明了</li></ul><p><strong>提高转化率</strong>：</p><ul><li>说明参与的价值和意义</li><li>提供清晰的行动指引</li><li>强调实验的简单和便捷</li><li>提供联系方式建立信任</li></ul><p><strong>个性化建议</strong>：</p><ul><li>根据收件人特点调整消息</li><li>使用友好、专业的语气</li><li>避免使用模板化的语言</li></ul><h3 id="_3-合理控制发送频率" tabindex="-1">3. 合理控制发送频率 <a class="header-anchor" href="#_3-合理控制发送频率" aria-label="Permalink to &quot;3. 合理控制发送频率&quot;">​</a></h3><p><strong>发送时机</strong>：</p><ul><li>选择合适的发送时间</li><li>避免在深夜或节假日发送</li><li>考虑收件人的时区</li></ul><p><strong>发送频率</strong>：</p><ul><li>不要频繁发送邮件</li><li>给收件人足够的考虑时间</li><li>如需提醒，间隔至少一周</li></ul><p><strong>跟进策略</strong>：</p><ul><li>对未回复的收件人适当跟进</li><li>跟进邮件要简短礼貌</li><li>尊重对方的选择</li></ul><h3 id="_4-遵守邮件营销规范" tabindex="-1">4. 遵守邮件营销规范 <a class="header-anchor" href="#_4-遵守邮件营销规范" aria-label="Permalink to &quot;4. 遵守邮件营销规范&quot;">​</a></h3><p><strong>法律法规</strong>：</p><ul><li>遵守反垃圾邮件法规</li><li>提供退订选项（如适用）</li><li>保护收件人隐私</li></ul><p><strong>平台规则</strong>：</p><ul><li>遵守CogniAND平台使用条款</li><li>不得进行虚假邀请</li><li>不得滥用邮件功能</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>⚠️ <strong>重要提示</strong>：</p><ol><li><p><strong>邮箱来源</strong></p><ul><li>确保邮箱来源合法</li><li>不要使用非���获取的邮箱列表</li><li>尊重收件人的隐私权</li></ul></li><li><p><strong>发送限制</strong></p><ul><li>单次发送建议不超过50个邮箱</li><li>避免短时间内大量发送</li><li>防止被识别为垃圾邮件</li></ul></li><li><p><strong>邮件内容</strong></p><ul><li>不要包含虚假信息</li><li>不要使用误导性的宣传</li><li>不要承诺无法兑现的奖励</li></ul></li><li><p><strong>隐私保护</strong></p><ul><li>不要在邮件中泄露其他被试的信息</li><li>使用密送（BCC）方式发送（如适用）</li><li>保护收件人的邮箱地址</li></ul></li><li><p><strong>垃圾邮件风险</strong></p><ul><li>避免使用垃圾邮件常用词汇</li><li>不要使用全大写或过多感叹号</li><li>提供真实的发件人信息</li></ul></li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-一次可以发送多少封邮件" tabindex="-1">Q1: 一次可以发送多少封邮件？ <a class="header-anchor" href="#q1-一次可以发送多少封邮件" aria-label="Permalink to &quot;Q1: 一次可以发送多少封邮件？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>建议单次发送不超过50个邮箱</li><li>过多可能被识别为垃圾邮件</li><li>如需大量发送，请分批进行</li></ul><h3 id="q2-邮件发送失败怎么办" tabindex="-1">Q2: 邮件发送失败怎么办？ <a class="header-anchor" href="#q2-邮件发送失败怎么办" aria-label="Permalink to &quot;Q2: 邮件发送失败怎么办？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>检查收件人邮箱地址是否正确</li><li>检查网络连接是否正常</li><li>稍后重试或联系技术支持</li></ul><h3 id="q3-收件人没有收到邮件怎么办" tabindex="-1">Q3: 收件人没有收到邮件怎么办？ <a class="header-anchor" href="#q3-收件人没有收到邮件怎么办" aria-label="Permalink to &quot;Q3: 收件人没有收到邮件怎么办？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>提醒收件人检查垃圾邮件文件夹</li><li>确认邮箱地址是否正确</li><li>确认邮件服务器是否正常</li><li>可以尝试重新发送</li></ul><h3 id="q4-可以撤回已发送的邮件吗" tabindex="-1">Q4: 可以撤回已发送的邮件吗？ <a class="header-anchor" href="#q4-可以撤回已发送的邮件吗" aria-label="Permalink to &quot;Q4: 可以撤回已发送的邮件吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>不可以，邮件发送后无法撤回</li><li>发送前请仔细检查内容</li><li>如有错误，可以发送更正邮件</li></ul><h3 id="q5-邀请消息可以包含链接吗" tabindex="-1">Q5: 邀请消息可以包含链接吗？ <a class="header-anchor" href="#q5-邀请消息可以包含链接吗" aria-label="Permalink to &quot;Q5: 邀请消息可以包含链接吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>可以，但建议只包含必要的链接</li><li>过多链接可能被识别为垃圾邮件</li><li>邀请链接会自动包含在邮件中</li></ul><h3 id="q6-如何提高邮件打开率" tabindex="-1">Q6: 如何提高邮件打开率？ <a class="header-anchor" href="#q6-如何提高邮件打开率" aria-label="Permalink to &quot;Q6: 如何提高邮件打开率？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>使用吸引人的邮件主题</li><li>选择合适的发送时间</li><li>确保邮件内容相关且有价值</li><li>避免被识别为垃圾邮件</li></ul><h3 id="q7-可以使用邮件模板吗" tabindex="-1">Q7: 可以使用邮件模板吗？ <a class="header-anchor" href="#q7-可以使用邮件模板吗" aria-label="Permalink to &quot;Q7: 可以使用邮件模板吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>可以，但建议根据收件人调整</li><li>避免使用完全相同的模板</li><li>个性化的邮件效果更好</li></ul><h3 id="q8-邮件发送记录会保存多久" tabindex="-1">Q8: 邮件发送记录会保存多久？ <a class="header-anchor" href="#q8-邮件发送记录会保存多久" aria-label="Permalink to &quot;Q8: 邮件发送记录会保存多久？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>记录保存在浏览器本地存储中</li><li>清除浏览器数据会删除记录</li><li>建议定期备份重要记录</li></ul><h3 id="q9-可以向同一个邮箱多次发送邀请吗" tabindex="-1">Q9: 可以向同一个邮箱多次发送邀请吗？ <a class="header-anchor" href="#q9-可以向同一个邮箱多次发送邀请吗" aria-label="Permalink to &quot;Q9: 可以向同一个邮箱多次发送邀请吗？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>可以，但不建议频繁发送</li><li>给收件人足够的考虑时间</li><li>过度发送可能被视为骚扰</li></ul><h3 id="q10-邮件邀请和链接分享有什么区别" tabindex="-1">Q10: 邮件邀请和链接分享有什么区别？ <a class="header-anchor" href="#q10-邮件邀请和链接分享有什么区别" aria-label="Permalink to &quot;Q10: 邮件邀请和链接分享有什么区别？&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li>邮件邀请：主动发送给特定收件人，更有针对性</li><li>链接分享：被动等待被试点击，覆盖面更广</li><li>两种方式可以结合使用，提高邀请效果</li></ul><hr><p><strong>需要更多帮助？</strong> 请查看：</p><ul><li><a href="/cogniand-manual.github.io/2-experimenter-manual/5-invite-system/5-1-generate-invite.html">生成邀请链接</a></li><li><a href="/cogniand-manual.github.io/2-experimenter-manual/5-invite-system/5-3-social-share.html">社交分享</a></li><li><a href="/cogniand-manual.github.io/3-subject-manual/5-personal-center.html">个人中心</a></li><li><a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a></li></ul>`,127)])])}const c=i(r,[["render",o]]);export{d as __pageData,c as default};
